#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find the predecessor of a node X
int findPredecessor(Node* root, int X) {
    Node* predecessor = NULL;
    while (root) {
        if (root->val < X) {
            predecessor = root;
            root = root->right;
        } else {
            root = root->left;
        }
    }
    return predecessor ? predecessor->val : -1;
}

int main() {
    int N, X;
    scanf("%d %d", &N, &X);
    Node* root = NULL;
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i+1);
    }
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        if (Ri == 'L') {
            nodes[pi-1]->left = nodes[ci-1];
        } else {
            nodes[pi-1]->right = nodes[ci-1];
        }
        if (!root) {
            root = nodes[0];
        }
    }
    int predecessor = findPredecessor(root, X);
    printf("%d\n", predecessor);
    return 0;
}

