import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        Node left;
        Node right;
        Node(int node_value) {
            val = node_value;
            left = right = null;
        }
    }

    // Function to find the predecessor of a node X
    public static int findPredecessor(Node root, int X) {
        Node predecessor = null;
        while (root != null) {
            if (root.val < X) {
                predecessor = root;
                root = root.right;
            } else {
                root = root.left;
            }
        }
        return predecessor != null ? predecessor.val : -1;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int X = scanner.nextInt();
        Node root = null;
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i+1);
        }
        for (int i = 0; i < N - 1; i++) {
            int pi = scanner.nextInt();
            int ci = scanner.nextInt();
            char Ri = scanner.next().charAt(0);
            if (Ri == 'L') {
                nodes[pi-1].left = nodes[ci-1];
            } else {
                nodes[pi-1].right = nodes[ci-1];
            }
            if (root == null) {
                root = nodes[0];
            }
        }
        int predecessor = findPredecessor(root, X);
        System.out.println(predecessor);
    }
}

